const input = $input.first().json;
const patients = input.body?.patients || input.patients || [];

const patientText = patients.map((p, i) => {
  const parts = [`${p.name}`];
  if (p.age && p.gender) parts.push(`${p.age}${p.gender}`);
  if (p.fbs_mgdl) parts.push(`FBS: ${p.fbs_mgdl} mg/dL`);
  if (p.exercise_minutes !== undefined && p.exercise_minutes !== '') parts.push(`Exercise: ${p.exercise_minutes} min`);
  if (p.food_diary) parts.push(`Food: ${p.food_diary}`);
  if (p.free_text) parts.push(`Notes: ${p.free_text}`);
  if (!p.fbs_mgdl && !p.free_text) parts.push('NO LOG SUBMITTED');
  return `Patient ${i+1}: ${parts.join(' — ')}`;
}).join('\n\n');

const systemPrompt = `You are MadhuMitra, a Clinical Protocol Intelligence Layer for diabetes reversal programs. You help health coaches triage their patient panel efficiently.

Active protocol (DiRECT/ADA baseline):
- Fasting glucose (FBS) threshold: >130 mg/dL = deviation, >180 mg/dL = high risk
- Post-meal glucose: >180 mg/dL = deviation
- Missed log = deviation signal, especially if repeated
- Minimum exercise: 30 min/day
- Symptom signals that ALWAYS = High severity regardless of glucose: foamy urine, blurry vision, persistent dizziness, chest pain, sudden weight loss

Three-step reasoning process:
1. CROSS-SIGNAL DETECTION: Identify threshold breaches AND symptom or distress signals in free-text. Combinations amplify risk: glucose deviation + missed exercise + negative mood = higher severity than any signal alone.
2. SENTIMENT DRIFT: Assess emotional tone. Words like terrible, dizzy, can't resist, skipping, very bad = negative drift. Words like great, motivated, on track, feeling good = positive.
3. RISK TIER ASSIGNMENT: Assign High, Medium, or Low severity AND a confidence level of high or low.

Critical rules:
- NEVER diagnose, prescribe, or give medical advice. Surface signals to the coach only.
- Every alert reason MUST cite specific data from the log: exact glucose numbers, exact phrases from free-text.
- High confidence = clear unambiguous signals, goes to auto track. Low confidence = ambiguous or borderline, goes to queue track.
- Patients with no deviations and positive/neutral tone go in on_track array.
- Return ONLY valid JSON. No markdown. No preamble. No explanation outside the JSON structure.`;

const userMessage = `Analyze today's patient logs and return structured JSON:

${patientText}

Return exactly this JSON structure with no other text:
{
  "alerts": [
    {
      "name": "patient name",
      "severity": "High|Medium|Low",
      "confidence": "high|low",
      "reason": "one-line reason citing specific log data",
      "signals": ["signal 1", "signal 2"],
      "track": "auto|queue"
    }
  ],
  "on_track": ["name1", "name2"],
  "summary": "one sentence summary of today's panel"
}

Sort alerts: High before Medium before Low. High-confidence cases go to track auto. Low-confidence cases go to track queue.`;

const requestBody = {
  model: 'claude-sonnet-4-20250514',
  max_tokens: 1500,
  system: systemPrompt,
  messages: [{ role: 'user', content: userMessage }]
};

return [{
  json: {
    requestBody: JSON.stringify(requestBody),
    patientCount: patients.length,
    timestamp: new Date().toISOString()
  }
}];

const response = $input.first().json;
const content = response.content || [];
const text = content.map(c => c.text || '').join('');
const clean = text.replace(/```json/g, '').replace(/```/g, '').trim();

try {
  const parsed = JSON.parse(clean);
  parsed.alerts = parsed.alerts || [];
  parsed.on_track = parsed.on_track || [];
  parsed.summary = parsed.summary || 'Analysis complete.';

  const highCount = parsed.alerts.filter(a => a.severity === 'High').length;
  const autoCount = parsed.alerts.filter(a => a.track === 'auto').length;
  const queueCount = parsed.alerts.filter(a => a.track === 'queue').length;

  return [{
    json: {
      success: true,
      data: parsed,
      meta: {
        high_priority: highCount,
        auto_list: autoCount,
        review_queue: queueCount,
        on_track: parsed.on_track.length,
        processed_at: new Date().toISOString()
      }
    }
  }];
} catch(e) {
  return [{
    json: {
      success: false,
      error: 'Failed to parse Claude response: ' + e.message,
      raw: text
    }
  }];
}
